void gemm_p128_q1_um32_un1_simd16_adaptive_half(const float* A, const float* B, float* C,
            int M, int N, int K) {
    for (int i = 0; i < M * N; ++i) C[i] = 0.0f;
    int ls = 0;
    while (ls < K) {
        int rem = K - ls;
        int min_l;
        if (rem >= 2 * 1) { min_l = 1; }
        else if (rem > 1) { min_l = ((rem / 2 + 32 - 1) / 32) * 32; }
        else { min_l = rem; }
        for (int row = 0; row < M; ++row) {
            for (int col = 0; col < N; ++col) {
                float partial = 0.0f;
                for (int k = ls; k < ls + min_l; ++k) {
                    partial += A[row * K + k] * B[k * N + col];
                }
                C[row * N + col] += partial;
            }
        }
        ls += min_l;
    }
}

