void gemm_p128_q512_um4_un4_simd4_adaptive_half(const float* A, const float* B, float* C,
            int M, int N, int K) {
    for (int i = 0; i < M * N; ++i) C[i] = 0.0f;
    int ls = 0;
    while (ls < K) {
        int rem = K - ls;
        int min_l;
        if (rem >= 2 * 512) { min_l = 512; }
        else if (rem > 512) { min_l = ((rem / 2 + 4 - 1) / 4) * 4; }
        else { min_l = rem; }
        for (int row = 0; row < M; ++row) {
            for (int col = 0; col < N; ++col) {
                float partial = 0.0f;
                for (int k = ls; k < ls + min_l; ++k) {
                    partial += A[row * K + k] * B[k * N + col];
                }
                C[row * N + col] += partial;
            }
        }
        ls += min_l;
    }
}

